[Form]
public class ETGVendTransaction extends FormRun
{
    QueryBuildRange closedVend;

}

/// <summary>
///
/// </summary>
public void init()
{            
    super();

    closedVend = this.query().dataSourceNo(1).addRange(fieldNum(VendTrans, Closed));
}

/// <summary>
///
/// </summary>
public void executeQuery()
{
    TransDate fromDateVal, toDateVal;
    TransDate emptyFromDate, emptyToDate;
    emptyFromDate = dateNull();
    emptyToDate = dateNull();
    fromDateVal    = 01\01\2012;
    toDateVal = today();

    if(ETGClosed.value() == NoYes::Yes)
    {
        //closedVend.value(SysQuery::range(fromDateVal, toDateVal));
        closedVend.value(SysQuery::valueEmptyString());
    }

    if(ETGClosed.value() == NoYes::No)
    {
        closedVend.value(SysQuery::range(emptyFromDate, emptyToDate));
    }

    super();                       
}
